class Solution:
    def minReversals(self, nums: list[int]) -> int:
        def is_stable(nums):
            for i in range(len(nums) - 1):
                if nums[i] > nums[i + 1]:
                    return False
            return True
        count = 0
        for i in range(len(nums)):
            if not is_stable(nums[:i] + nums[i + 1:]):
                count += 1
                if i < len(nums) - 1:
                    nums[i:i + 2] = nums[i + 2:i:-1]
        return count
    @staticmethod
    def main():
        import sys
        for line in sys.stdin.readline().splitlines():
            nums = list(map(int, line.split()))
            solution = Solution()
            print(solution.minReversals(nums))

