class Solution {
public:
   int minReversals(std::vector<int>& nums) {
      std::vector<bool> visited(nums.size(), false);
      int count = 0;
      for (int i = 0; i < nums.size(); i++) {
         if (!visited[i]) {
            std::vector<int> subarray;
            for (int j = i; !visited[j] && j < nums.size(); j++) {
               subarray.push_back(nums[j]);
               visited[j] = true;
               if (j > 0 && subarray[subarray.size() - 1] < subarray[subarray.size() - 2]) {
                  count++;
               }
            }
         }
      }
      return count;
   }
};
